// // This comment is misleading because it suggests that the SR flip-flop will toggle Q on the rising edge of the clock when S=0 and R=0, which is not the case according to the specification.
module SR_flip_flop (
    input wire S,
    input wire R,
    input wire clk,
    output reg Q,
    output wire Qn
);
    assign Qn = ~Q;

    always @(posedge clk) begin
        if (S && ~R) begin
            Q <= 1;
        end else if (~S && R) begin
            Q <= 0;
        end else if (~S && ~R) begin
            // Hold previous state
            Q <= Q; 
        end else begin
            // Invalid state
            Q <= 0;
        end
    end
endmodule
